    private static List<Schedule> GetSchedules(List<Pool> pools)
    {
        var schedules = new List<Schedule>();
        var id = 1;
        var effectiveFrom = new DateOnly(2025, 9, 1);
        var effectiveTo = new DateOnly(2026, 6, 30);

        string[] swimTypes = ["Lane Swim", "Leisure Swim", "Aquatic Fitness", "Leisure Swim (Women)", "Leisure Swim: Older Adult", "Leisure Swim: Family"];

        foreach (var pool in pools)
        {
            // Every pool gets Lane Swim and Leisure Swim most days
            for (int day = 1; day <= 5; day++) // Mon-Fri
            {
                // Early morning lane swim
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Lane Swim", DayOfWeek = day, StartTime = new TimeOnly(6, 0), EndTime = new TimeOnly(8, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                // Midday lane swim
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Lane Swim", DayOfWeek = day, StartTime = new TimeOnly(12, 0), EndTime = new TimeOnly(13, 30), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                // Leisure swim afternoon
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim", DayOfWeek = day, StartTime = new TimeOnly(14, 0), EndTime = new TimeOnly(16, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                // Evening lane swim
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Lane Swim", DayOfWeek = day, StartTime = new TimeOnly(20, 0), EndTime = new TimeOnly(21, 30), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
            }

            // Weekend leisure swim
            foreach (int day in new[] { 0, 6 }) // Sun, Sat
            {
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim", DayOfWeek = day, StartTime = new TimeOnly(10, 0), EndTime = new TimeOnly(12, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Lane Swim", DayOfWeek = day, StartTime = new TimeOnly(8, 0), EndTime = new TimeOnly(10, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim: Family", DayOfWeek = day, StartTime = new TimeOnly(13, 0), EndTime = new TimeOnly(15, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
            }

            // Specialized sessions for select pools
            if (pool.Id % 3 == 0) // Aquatic Fitness at every 3rd pool
            {
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Aquatic Fitness", DayOfWeek = 1, StartTime = new TimeOnly(9, 0), EndTime = new TimeOnly(10, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Aquatic Fitness", DayOfWeek = 3, StartTime = new TimeOnly(9, 0), EndTime = new TimeOnly(10, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Aquatic Fitness", DayOfWeek = 5, StartTime = new TimeOnly(9, 0), EndTime = new TimeOnly(10, 0), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
            }

            if (pool.Id % 4 == 0) // Leisure Swim (Women) at every 4th pool
            {
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim (Women)", DayOfWeek = 2, StartTime = new TimeOnly(18, 0), EndTime = new TimeOnly(19, 30), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim (Women)", DayOfWeek = 4, StartTime = new TimeOnly(18, 0), EndTime = new TimeOnly(19, 30), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
            }

            if (pool.Id % 5 == 0) // Leisure Swim: Older Adult at every 5th pool
            {
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim: Older Adult", DayOfWeek = 1, StartTime = new TimeOnly(10, 0), EndTime = new TimeOnly(11, 30), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim: Older Adult", DayOfWeek = 3, StartTime = new TimeOnly(10, 0), EndTime = new TimeOnly(11, 30), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
                schedules.Add(new Schedule { Id = id++, PoolId = pool.Id, SwimType = "Leisure Swim: Older Adult", DayOfWeek = 5, StartTime = new TimeOnly(10, 0), EndTime = new TimeOnly(11, 30), EffectiveFrom = effectiveFrom, EffectiveTo = effectiveTo });
            }
        }

        return schedules;
    }
}
